#include <vector>

namespace batch_insert_products {

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  std::string name;
  float price;
  std::string category;
  int stock;
};

/**
 * Function: Perform efficient batch insertion of product data using a transaction.
 * 
 * @param products List of products to insert
 * @return true if all inserts succeed, false otherwise
 */
bool batch_insert_products(const std::vector<Product>& products) {
    // 1. Connect to the database
    auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
    if (!conn_result) {
        return false;
    }
    auto conn = conn_result.value();

    // 2. Drop the table if it exists
    auto drop_result = (sqlgen::drop<Product> | sqlgen::if_exists)(conn);
    if (!drop_result) {
        return false;
    }

    // 3. Begin a transaction
    auto begin_result = conn->begin_transaction();
    if (!begin_result) {
        return false;
    }

    // 4. Insert the products using batch operation
    // Convert the vector to a range
    auto products_range = products.begin(), products_end = products.end();

    // Use sqlgen::insert to perform batch insertion
    auto insert_result = sqlgen::insert(conn, products_range, products_end);
    if (!insert_result) {
        // If insertion fails, rollback the transaction
        conn->rollback();
        return false;
    }

    // 5. Commit the transaction
    auto commit_result = conn->commit();
    if (!commit_result) {
        conn->rollback();
        return false;
    }

    return true;
}

}  // namespace batch_insert_products
```

