namespace delete_inactive_users {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
  std::optional<sqlgen::DateTime> last_login;
  std::string status = "active";
};

int delete_inactive_users() {
  // Connect to the SQLite database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return -1; // Connection failed
  }
  auto conn = conn_result.value();

  // Begin transaction
  auto begin_result = conn->begin_transaction();
  if (!begin_result) {
    return -1; // Transaction begin failed
  }

  try {
    // Create delete query with where condition
    auto delete_query = sqlgen::delete_from<User> 
                      | sqlgen::where("last_login"_c < "2025-01-01");

    // Execute the delete operation
    auto delete_result = delete_query(conn);
    if (!delete_result) {
      // Rollback on delete failure
      auto rollback_result = conn->rollback();
      return -1; // Delete operation failed
    }

    // Commit transaction on success
    auto commit_result = conn->commit();
    if (!commit_result) {
      // Rollback on commit failure
      auto rollback_result = conn->rollback();
      return -1; // Commit failed
    }

    return 0; // Success

  } catch (const std::exception& e) {
    // Rollback on exception
    auto rollback_result = conn->rollback();
    return -1; // Exception occurred
  }
}

} // namespace delete_inactive_users
```

