    auto result = sqlgen::create_table<Customer>(conn);
    if (!result) return false;

    result = sqlgen::create_table<Order>(conn);
    if (!result) return false;

    result = sqlgen::create_table<OrderItem>(conn);
    if (!result) return false;

    result = sqlgen::create_table<Product>(conn);
    return result;
  };

