#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace soft_delete_records {

struct Document {
  sqlgen::PrimaryKey<int> doc_id;
  std::string title;
  int is_deleted = 0;
  std::optional<sqlgen::DateTime> deleted_at;
};

bool soft_delete_records(const std::vector<int>& ids) {
    using namespace sqlgen::literals;

    // 1. Connect to the SQLite database
    auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
    if (!conn_result) {
        return false;
    }
    auto conn = *conn_result;

    // 2. Create update statement with IN clause for doc_ids
    auto update_stmt = sqlgen::update<Document>(
        "is_deleted"_c.set(1),
        "deleted_at"_c.set(sqlgen::current_timestamp)
    ) | sqlgen::where("doc_id"_c.in(ids));

    // 3. Execute the update within a transaction
    auto begin_result = conn->begin_transaction();
    if (!begin_result) {
        return false;
    }

    auto execute_result = update_stmt(conn);
    if (!execute_result) {
        conn->rollback();
        return false;
    }

    auto commit_result = conn->commit();
    if (!commit_result) {
        conn->rollback();
        return false;
    }

    return true;
}

}  // namespace soft_delete_records
```

