#include <sqlgen/sqlite.hpp>

namespace update_order_status {

struct Order {
  sqlgen::PrimaryKey<int> order_id;
  std::string status;
  sqlgen::DateTime order_date;
  double total_amount;
};

int update_order_status() {
  using namespace sqlgen::literals;

  // 1. Connect to the SQLite database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return -1; // Connection failed
  }
  auto conn = *conn_result;

  // 2. Create UPDATE statement for pending orders older than 7 days
  auto pending_update = sqlgen::update<Order>("status"_c.set("expired"))
    | sqlgen::where(("status"_c == "pending") && ("order_date"_c < sqlgen::date_plus_duration(sqlgen::current_date(), -7, "days")));

  // 3. Create UPDATE statement for shipped orders
  auto shipped_update = sqlgen::update<Order>("status"_c.set("delivered"))
    | sqlgen::where(("status"_c == "shipped") && ("order_date"_c < sqlgen::date_plus_duration(sqlgen::current_date(), -7, "days")));

  // 4. Execute both UPDATE statements and handle results
  auto pending_result = pending_update(conn);
  auto shipped_result = shipped_update(conn);

  // 5. Return the number of rows affected
  if (pending_result && shipped_result) {
    return pending_result->affected_rows() + shipped_result->affected_rows();
  }

  return -1; // Error occurred during execution
}

} // namespace update_order_status
