namespace analyze_social_network {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
  std::string email;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> join_date;
  std::optional<std::string> city;
};

struct Friendship {
  int user1_id;
  int user2_id;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> created_at;
  sqlgen::PrimaryKey<std::pair<int, int>> composite_key;
};

struct FriendConnection {
  std::string user1_name;
  std::string user2_name;
  int mutual_friends;
};

/**
 * Analyze social network data by creating temporary SQL tables for User and Friendship.
 * Returns: std::vector<FriendConnection>.
 */
std::vector<FriendConnection> analyze_social_network_impl(const std::vector<User>& users, const std::vector<Friendship>& friendships) {
  using namespace sqlgen::literals;

  // Connect to SQLite database
  auto conn_result = sqlgen::sqlite::connect(":memory:");
  if (!conn_result) {
    throw std::runtime_error("Failed to connect to database");
  }
  auto conn = conn_result.value();

  // Create tables for User and Friendship
  auto user_table = sqlgen::create_table<User>;
  auto friendship_table = sqlgen::create_table<Friendship>;

  // Insert sample data
  auto insert_users = sqlgen::insert(users.begin(), users.end());
  auto insert_friendships = sqlgen::insert(friendships.begin(), friendships.end());

  // Query 1: Mutual friends using SELF-JOIN
  auto mutual_friends_query = sqlgen::select_from<User>(
      "username"_c,
      "username"_c,
      sqlgen::count("user2_id"_c).as("mutual_friends")
  ) | sqlgen::inner_join<Friendship>("user1_id"_c == "user_id"_c) |
  sqlgen::inner_join<Friendship>("user2_id"_c == "user_id"_c) |
  sqlgen::where("user_id"_c < "user_id"_c) |
  sqlgen::group_by("user_id"_c, "user_id"_c);

  // Query 2: Users with more than N friends using nested query
  auto popular_users_query = sqlgen::select_from<User>(
      "username"_c,
      sqlgen::count("user2_id"_c).as("friend_count")
  ) | sqlgen::left_join<Friendship>("user_id"_c == "user1_id"_c) |
  sqlgen::where(sqlgen::count("user2_id"_c) > sqlgen::select_from<User>(
      sqlgen::count("user2_id"_c).as("avg_friends")
  ).avg());

  // Query 3: Friend-of-friend relationships
  auto friend_of_friend_query = sqlgen::select_from<User>(
      "username"_c,
      "username"_c
  ) | sqlgen::inner_join<Friendship>("user1_id"_c == "user_id"_c) |
  sqlgen::inner_join<Friendship>("user2_id"_c == "user_id"_c) |
  sqlgen::where("user_id"_c != "user_id"_c);

  // Query 4: Most connected users
  auto most_connected_query = sqlgen::select_from<User>(
      "username"_c,
      sqlgen::count("user2_id"_c).as("friend_count")
  ) | sqlgen::left_join<Friendship>("user_id"_c == "user1_id"_c) |
  sqlgen::group_by("user_id"_c) |
  sqlgen::order_by(sqlgen::count("user2_id"_c).desc());

  // Query 5: City recommendations
  auto city_recommendations_query = sqlgen::select_from<User>(
      "username"_c,
      "username"_c
  ) | sqlgen::where("city"_c.is_not_null()) |
  sqlgen::where(!sqlgen::exists(sqlgen::select_from<Friendship>(
      "user1_id"_c == "user_id"_c && "user2_id"_c == "user_id"_c
 )));

  // Execute queries and process results
  auto mutual_results = mutual_friends_query(conn).value();
  auto popular_results = popular_users_query(conn).value();
  auto friend_of_friend_results = friend_of_friend_query(conn).value();
  auto most_connected_results = most_connected_query(conn).value();
