  auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  // Read from UserProfile table and apply trimming/length operations
  return sqlgen::read<std::vector<UserProfile>>
      .and_then([](const auto& profiles) {
        // Transform UserProfile to ValidatedProfile with trimming and length measurements
        return sqlgen::transform(
            profiles,
