};

struct JoinResult {
  std::optional<std::string> department_name;
  std::optional<std::string> first_name;
  std::optional<std::string> last_name;
  std::optional<double> salary;
};

struct JoinAnalysis {
  std::vector<JoinResult> inner_join_results;
  std::vector<JoinResult> left_join_results;
  std::vector<JoinResult> right_join_results;
  std::vector<JoinResult> full_join_results;
};

/**
 * analyze_department_employees
 * Provides data-join analysis between Department and Employee input collections by
 * creating temporary SQL tables, inserting the provided rows, and executing a
 * variety of join queries to produce join-output samples.
 * Returns: JoinAnalysis.
 */
JoinAnalysis analyze_department_employees_impl(const std::vector<Department>& depts, const std::vector<Employee>& emps) {
  // Connect to SQLite database
  auto conn_result = sqlgen::sqlite::connect();
  if (!conn_result) {
    throw std::runtime_error("Failed to connect to database");
  }
  auto conn = conn_result.value();

  // Create temporary tables
  auto dept_table = sqlgen::create_table<Department>;
  auto emp_table = sqlgen::create_table<Employee>;

  // Insert data into tables
  auto dept_insert = sqlgen::insert(conn, depts);
  auto emp_insert = sqlgen::insert(conn, emps);

  if (!dept_insert || !emp_insert) {
    throw std::runtime_error("Failed to insert data");
  }

  // Define column references with table aliases
  using namespace sqlgen::literals;
  auto d = "d"_t1;  // Department table alias
  auto e = "e"_t2;  // Employee table alias

  // Build INNER JOIN query
  auto inner_join_query = sqlgen::select_from<Department, "d">(
      d["department_name"],
      e["first_name"],
      e["last_name"],
      e["salary"]
  ) | sqlgen::join<Employee, "e">(d["department_id"] == e["department_id"])
    | sqlgen::to<std::vector<JoinResult>>;

  // Build LEFT JOIN query
  auto left_join_query = sqlgen::select_from<Employee, "e">(
      d["department_name"],
      e["first_name"],
      e["last_name"],
      e["salary"]
  ) | sqlgen::left_join<Department, "d">(e["department_id"] == d["department_id"])
    | sqlgen::to<std::vector<JoinResult>>;

  // Build RIGHT JOIN query
  auto right_join_query = sqlgen::select_from<Department, "d">(
      d["department_name"],
      e["first_name"],
      e["last_name"],
      e["salary"]
  ) | sqlgen::right_join<Employee, "e">(d["department_id"] == e["department_id"])
    | sqlgen::to<std::vector<JoinResult>>;

  // Build FULL JOIN query
  auto full_join_query = sqlgen::select_from<Department, "d">(
      d["department_name"],
      e["first_name"],
      e["last_name"],
      e["salary"]
  ) | sqlgen::full_join<Employee, "e">(d["department_id"] == e["department_id"])
    | sqlgen::to<std::vector<JoinResult>>;

  // Execute queries and extract results
  auto inner_results = inner_join_query(conn).value();
  auto left_results = left_join_query(conn).value();
  auto right_results = right_join_query(conn).value();
  auto full_results = full_join_query(conn).value();

  // Transform results to match JoinResult structure
  auto transform_result = [](const auto& result) -> JoinResult {
    return JoinResult{
        .department_name = result.department_name,
        .first_name = result.first_name,
        .last_name = result.last_name,
        .salary = result.salary
    };
  };

  // Populate analysis structure
  JoinAnalysis analysis;
  analysis.inner_join_results = sqlgen::internal::collect::vector(
      inner_results | std::ranges::views::transform(transform_result));
  analysis.left_join_results = sqlgen::internal::collect::vector(
