  const auto query =
      select_from<Order, "o">(col<"order_id", "o"> | as<"order_id">,
                              col<"customer", "o"> | as<"customer">,
                              sum(col<"unit_price", "oi"> * col<"quantity", "oi">) |
                                  as<"total">) |
      inner_join<OrderItem, "oi">(col<"order_id", "o"> == col<"order_id", "oi">) |
